with (common table expressions).syntax:
WITH cte_name AS (
    SELECT column1, column2
    FROM table_name
    WHERE condition
)
SELECT * FROM cte_name;

postgresql.notes:
Native MERGE support since PostgreSQL 15
Prior to this version, use
WITH upsert AS (
  UPDATE t SET … WHERE … RETURNING *
)
INSERT INTO t (…) SELECT … WHERE NOT EXISTS (SELECT 1 FROM upsert);

json_table.syntax:
SELECT jt.*
FROM my_table,
JSON_TABLE(json_col, '$' COLUMNS (
    name VARCHAR(100) PATH '$.name',
    age  INT           PATH '$.age'
)) AS jt;

mysql.syntax:
SELECT jt.*
FROM tbl,
JSON_TABLE(json_col, '$' COLUMNS (
  name VARCHAR(50) PATH '$.name',
  age  INT           PATH '$.age'
)) AS jt;

oracle.syntax:
SELECT jt.name, jt.age
FROM tbl,
JSON_TABLE(json_col, '$'
  COLUMNS (name VARCHAR2(50) PATH '$.name', age NUMBER PATH '$.age')
) jt;

window functions.syntax:
SELECT column1,
       AVG(column3) OVER (PARTITION BY column1 ORDER BY column2) AS avg_val
FROM table_name;

mysql.syntax:
SELECT col1,
       ROW_NUMBER() OVER (PARTITION BY col1 ORDER BY col2) AS rn
FROM tbl;

postgresql.syntax:
SELECT col1,
       RANK()      OVER (PARTITION BY col1 ORDER BY col2) AS rnk
FROM tbl;

sqlserver.syntax:
SELECT col1,
       LAG(col2)   OVER (PARTITION BY col1 ORDER BY col2) AS prev_val
FROM tbl;

oracle.syntax:
SELECT col1,
       FIRST_VALUE(col2) OVER (PARTITION BY col1 ORDER BY col2) AS first_val
FROM tbl;

sqlite.syntax:
SELECT col1,
       SUM(col2)  OVER (PARTITION BY col1) AS total
FROM tbl;

pivot.syntax:
SELECT *
FROM (
  SELECT category, month, value
  FROM sales
) AS src
PIVOT (
  SUM(value) FOR month IN ([Jan],[Feb],[Mar])
) AS p;

postgresql.syntax:
SELECT *
FROM crosstab(
  'SELECT category,month,value FROM sales ORDER BY 1,2',
  'VALUES (''Jan''),( ''Feb''),( ''Mar'')'
) AS ct(category text, Jan int, Feb int, Mar int);

sqlserver.syntax:
SELECT *
FROM (
  SELECT category, month, value FROM sales
) AS src
PIVOT(
  SUM(value) FOR month IN ([Jan],[Feb],[Mar])
) AS p;

oracle.syntax:
SELECT *
FROM (
  SELECT category, month, value FROM sales
)
PIVOT(
  SUM(value) FOR month IN ('Jan' AS Jan,'Feb' AS Feb,'Mar' AS Mar)
);

mysql.syntax:
SELECT *
FROM articles
WHERE MATCH(title,body) AGAINST('terms' IN BOOLEAN MODE);

sqlserver.syntax:
SELECT *
FROM articles
WHERE CONTAINS((title,body),'"terms"');

oracle.syntax:
SELECT *
FROM articles
WHERE CONTAINS(title||body,'terms')>0;

sqlite.syntax:
SELECT rowid, *
FROM articles_fts
WHERE articles_fts MATCH 'terms';

sqlserver.syntax:
SELECT TOP 10 * FROM tbl WHERE … ORDER BY col;
-- or with OFFSET FETCH:
SELECT * FROM tbl WHERE … ORDER BY col
OFFSET 5 ROWS FETCH NEXT 10 ROWS ONLY;

INSERT INTO tbl (c1,c2)
OUTPUT inserted.id
VALUES (v1,v2);

oracle.syntax:
INSERT INTO tbl (c1,c2)
VALUES (v1,v2)
RETURNING id INTO :new_id;

update.syntax:
UPDATE table_name
SET col1 = v1, col2 = v2
WHERE condition;

sqlserver.syntax:
DELETE FROM tbl
OUTPUT deleted.*
WHERE …;

