comments.syntax:
-- single-line comment

/* block comment
   spans multiple lines */

SELECT col -- inline comment
FROM tbl;

mysql.syntax:
-- single-line
/* block */
/*!50700 SELECT 'MySQL 5.7+'; */

postgresql.syntax:
-- single-line
/* block */
/* outer /* nested */ still a comment */

oracle.syntax:
-- single-line
/* block */
SELECT /*+ FULL(t) */ * FROM t;

join.syntax:
SELECT a.col, b.col
FROM table_a a
JOIN table_b b ON a.id = b.a_id;

inner join.syntax:
SELECT a.col, b.col
FROM table_a a
INNER JOIN table_b b ON a.id = b.a_id;

left join.syntax:
SELECT a.col, b.col
FROM table_a a
LEFT JOIN table_b b ON a.id = b.a_id;

right join.syntax:
SELECT a.col, b.col
FROM table_a a
RIGHT JOIN table_b b ON a.id = b.a_id;

full outer join.syntax:
SELECT a.col, b.col
FROM table_a a
FULL OUTER JOIN table_b b ON a.id = b.a_id;

mysql.syntax:
SELECT a.col, b.col FROM a LEFT JOIN b ON a.id = b.id
UNION
SELECT a.col, b.col FROM a RIGHT JOIN b ON a.id = b.id;

cross join.syntax:
SELECT a.col, b.col
FROM table_a a
CROSS JOIN table_b b;

mysql.syntax:
CREATE INDEX idx ON tbl (col);
CREATE UNIQUE INDEX idx ON tbl (col);
CREATE FULLTEXT INDEX idx ON tbl (col);

sqlserver.syntax:
CREATE INDEX idx ON tbl (col);
CREATE CLUSTERED INDEX idx ON tbl (col);
CREATE INDEX idx ON tbl (col) WHERE active = 1;  -- filtered

oracle.syntax:
CREATE INDEX idx ON tbl (col);
CREATE BITMAP INDEX idx ON tbl (col);
CREATE INDEX idx ON tbl (UPPER(col));  -- function-based

postgresql.syntax:
CREATE VIEW v AS SELECT col FROM tbl;
CREATE MATERIALIZED VIEW mv AS SELECT col FROM tbl;
REFRESH MATERIALIZED VIEW CONCURRENTLY mv;

sqlserver.syntax:
CREATE VIEW v AS SELECT col FROM tbl;
-- Materialize it:
CREATE UNIQUE CLUSTERED INDEX idx ON v (col);

oracle.syntax:
CREATE VIEW v AS SELECT col FROM tbl;
CREATE MATERIALIZED VIEW mv
REFRESH ON DEMAND AS SELECT col FROM tbl;

SELECT COALESCE(a, b, 'default') FROM tbl;
SELECT NVL(a, 'default') FROM tbl;
SELECT NVL2(a, 'has value', 'is null') FROM tbl;

postgresql.syntax:
SELECT CAST(price AS TEXT) FROM tbl;
SELECT price::text FROM tbl;  -- :: shorthand
SELECT '2024-01-01'::date;
SELECT '42'::int + 1;

oracle.syntax:
SELECT CAST(price AS VARCHAR2(20)) FROM tbl;
SELECT TO_CHAR(hire_date, 'YYYY-MM-DD') FROM tbl;
SELECT TO_NUMBER('42.5') FROM DUAL;

subquery.syntax:
-- Scalar subquery in WHERE:
SELECT name FROM employees
WHERE salary > (SELECT AVG(salary) FROM employees);

-- Correlated subquery:
SELECT name FROM employees e
WHERE salary > (
  SELECT AVG(salary) FROM employees
  WHERE dept_id = e.dept_id
);

postgresql.syntax:
CREATE FUNCTION set_updated_at() RETURNS trigger LANGUAGE plpgsql AS $$
BEGIN NEW.updated_at = now(); RETURN NEW; END;
$$;

CREATE TRIGGER trg BEFORE UPDATE ON tbl
FOR EACH ROW EXECUTE FUNCTION set_updated_at();

sqlserver.syntax:
CREATE TRIGGER trg ON tbl AFTER INSERT AS
BEGIN
  UPDATE tbl SET updated_at = GETDATE()
  WHERE id IN (SELECT id FROM inserted);
END;

sqlite.syntax:
CREATE TRIGGER trg AFTER INSERT ON tbl
BEGIN
  UPDATE tbl SET updated_at = datetime('now') WHERE id = NEW.id;
END;

stored procedure.syntax:
-- MySQL / SQL Server style:
CREATE PROCEDURE proc_name(IN param1 INT)
BEGIN
  SELECT * FROM tbl WHERE id = param1;
END;

mysql.syntax:
CREATE PROCEDURE get_user(IN uid INT)
BEGIN
  SELECT * FROM users WHERE id = uid;
END;

CALL get_user(42);

postgresql.syntax:
CREATE PROCEDURE update_balance(uid INT, amount NUMERIC)
LANGUAGE plpgsql AS $$
BEGIN
  UPDATE accounts SET balance = balance + amount WHERE id = uid;
  COMMIT;
END;
$$;

CALL update_balance(1, 100.00);

sqlserver.syntax:
CREATE PROCEDURE get_user @uid INT AS
BEGIN
  SELECT * FROM users WHERE id = @uid;
END;

EXEC get_user 42;

oracle.syntax:
CREATE PROCEDURE get_user(uid IN NUMBER) AS
BEGIN
  SELECT * FROM users WHERE id = uid;
EXCEPTION WHEN OTHERS THEN NULL;
END;

EXEC get_user(42);

mysql.syntax:
EXPLAIN SELECT * FROM tbl WHERE col = 1;
EXPLAIN ANALYZE SELECT * FROM tbl WHERE col = 1;  -- 8.0.18+
EXPLAIN FORMAT=TREE SELECT * FROM tbl WHERE col = 1;

postgresql.syntax:
EXPLAIN SELECT * FROM tbl WHERE col = 1;
EXPLAIN ANALYZE SELECT * FROM tbl WHERE col = 1;
EXPLAIN (ANALYZE, BUFFERS, FORMAT JSON) SELECT * FROM tbl WHERE col = 1;

sqlserver.syntax:
SET SHOWPLAN_XML ON;
GO
SELECT * FROM tbl WHERE col = 1;
GO
SET SHOWPLAN_XML OFF;
-- Or: SET STATISTICS IO ON; SET STATISTICS TIME ON;

listen/notify.syntax:
-- Session 1 (subscriber):
LISTEN order_updates;

-- Session 2 (publisher):
NOTIFY order_updates, '{"id": 42}';

postgresql.syntax:
-- Session 1:
LISTEN order_updates;

-- Session 2:
NOTIFY order_updates, '{"id": 42, "status": "shipped"}';

-- From inside a trigger:
SELECT pg_notify('order_updates', row_to_json(NEW)::text);

generate_series.syntax:
SELECT * FROM generate_series(1, 10) AS n;

-- Calendar of months:
SELECT generate_series(
  '2024-01-01'::date,
  '2024-12-01',
  '1 month'
)::date AS month;

mysql.syntax:
WITH RECURSIVE n AS (
  SELECT 1 AS val
  UNION ALL
  SELECT val + 1 FROM n WHERE val < 10
)
SELECT val FROM n;

postgresql.syntax:
SELECT generate_series(1, 10);
SELECT generate_series(1, 10, 2);  -- odd numbers: 1,3,5,7,9
SELECT generate_series(
  '2024-01-01'::timestamptz,
  '2024-12-31',
  '1 month'
) AS month;

sqlserver.syntax:
SELECT value FROM GENERATE_SERIES(1, 10);
SELECT value FROM GENERATE_SERIES(1, 10, 2);
-- Requires: ALTER DATABASE db SET COMPATIBILITY_LEVEL = 160;

sqlite.syntax:
WITH RECURSIVE n(val) AS (
  SELECT 1
  UNION ALL
  SELECT val + 1 FROM n WHERE val < 10
)
SELECT val FROM n;

returning.syntax:
INSERT INTO users (name) VALUES ('Alice') RETURNING id, created_at;

UPDATE orders SET status = 'shipped' WHERE id = 42 RETURNING *;

DELETE FROM sessions WHERE expired_at < NOW() RETURNING session_id;

postgresql.syntax:
INSERT INTO users (name) VALUES ('Alice') RETURNING id, created_at;
UPDATE orders SET status = 'shipped' WHERE id = 42 RETURNING *;
DELETE FROM sessions WHERE expired_at < NOW() RETURNING session_id;

sqlserver.syntax:
INSERT INTO users (name) OUTPUT INSERTED.id, INSERTED.name VALUES ('Alice');
UPDATE orders SET status = 'shipped' OUTPUT INSERTED.*, DELETED.status WHERE id = 42;
DELETE FROM sessions OUTPUT DELETED.session_id WHERE expired_at < GETDATE();

exclusion constraints.syntax:
CREATE TABLE bookings (
  room   INT,
  during TSRANGE,
  EXCLUDE USING gist (room WITH =, during WITH &&)
);

mysql.syntax:
-- Not supported.
SELECT * FROM bookings
WHERE start_date < '2024-02-01' AND end_date > '2024-01-01';

postgresql.syntax:
SELECT '[1,5)'::int4range @> 3;   -- true
SELECT '[1,5)'::int4range && '[3,8)'::int4range;  -- true

CREATE TABLE events (
  name   TEXT,
  during TSRANGE
);
CREATE INDEX ON events USING gist (during);

-- Query events overlapping a window:
SELECT * FROM events
WHERE during && '[2024-01-01,2024-02-01)'::tsrange;

oracle.syntax:
SELECT
  PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY salary) AS median
FROM employees;

SELECT STATS_MODE(dept_id) AS most_common_dept FROM employees;

row-level security.syntax:
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;

CREATE POLICY own_orders ON orders
  USING (customer_id = current_setting('app.user_id')::int);

mysql.syntax:
-- Not supported. Workaround: a view with a WHERE clause
CREATE VIEW my_orders AS
  SELECT * FROM orders WHERE customer_id = GET_USER_ID();

postgresql.syntax:
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE orders FORCE ROW LEVEL SECURITY;

-- Allow users to see only their own rows:
CREATE POLICY own_orders ON orders FOR SELECT
  USING (customer_id = current_setting('app.user_id')::int);

-- Allow admins to see everything:
CREATE POLICY admin_all ON orders FOR ALL TO admin_role
  USING (true);

sqlserver.syntax:
CREATE FUNCTION dbo.rls_fn(@cust_id INT)
RETURNS TABLE WITH SCHEMABINDING AS
RETURN SELECT 1 AS ok WHERE @cust_id = CAST(SESSION_CONTEXT(N'user_id') AS INT);

CREATE SECURITY POLICY dbo.OrderPolicy
ADD FILTER PREDICATE dbo.rls_fn(customer_id) ON dbo.orders
WITH (STATE = ON);

oracle.syntax:
CREATE FUNCTION rls_policy(schema_v VARCHAR2, tbl VARCHAR2)
RETURN VARCHAR2 AS
BEGIN RETURN 'customer_id = SYS_CONTEXT(''USERENV'',''SESSION_USER'')'; END;

BEGIN
  DBMS_RLS.ADD_POLICY('SCOTT','ORDERS','own_orders','SCOTT','rls_policy');
END;

postgresql.syntax:
SELECT * FROM tbl TABLESAMPLE BERNOULLI(10);
SELECT * FROM tbl TABLESAMPLE SYSTEM(10);
SELECT * FROM tbl TABLESAMPLE BERNOULLI(5) REPEATABLE(42);  -- reproducible
-- With extension:
SELECT * FROM tbl TABLESAMPLE SYSTEM_ROWS(1000);  -- exact row count

oracle.syntax:
SELECT * FROM tbl SAMPLE(10);         -- row-level ~10%
SELECT * FROM tbl SAMPLE BLOCK(10);   -- page-level ~10%
SELECT * FROM tbl SAMPLE(10) SEED(42);

sqlite.syntax:
SELECT * FROM tbl WHERE rowid IN (
  SELECT rowid FROM tbl ORDER BY RANDOM() LIMIT 1000
);

SELECT CONCAT('Hello', ' ', 'World');       -- 3.44.0+
SELECT 'Hello' || ' ' || 'World';          -- all versions
SELECT COALESCE(name, '') || ' ' || COALESCE(suffix, '') FROM tbl;

sqlserver.syntax:
SELECT SUBSTRING('Hello World', 7, 5);     -- 'World'
-- Last 5 chars:
SELECT SUBSTRING(col, LEN(col) - 4, 5) FROM tbl;

date trunc.syntax:
-- Truncate to start of month:
SELECT DATE_TRUNC('month', created_at) AS month_start
FROM orders;

mysql.syntax:
-- Truncate to start of month:
SELECT DATE_FORMAT(created_at, '%Y-%m-01') AS month_start FROM orders;
-- Truncate to start of hour:
SELECT DATE_FORMAT(created_at, '%Y-%m-%d %H:00:00') AS hour_start FROM orders;

sqlserver.syntax:
-- SQL Server 2022+:
SELECT DATE_TRUNC(month, created_at) FROM orders;

-- Older versions (workaround):
SELECT DATEADD(month, DATEDIFF(month, 0, created_at), 0) FROM orders;
SELECT DATEADD(day,   DATEDIFF(day,   0, created_at), 0) FROM orders;

sqlite.syntax:
-- Truncate to start of month:
SELECT strftime('%Y-%m-01', created_at) FROM orders;
-- Truncate to start of hour:
SELECT strftime('%Y-%m-%d %H:00:00', created_at) FROM orders;

