mysql.syntax:
SELECT * FROM users WHERE phone IS NULL;
SELECT * FROM users WHERE phone IS NOT NULL;
SELECT * FROM tbl WHERE col <=> NULL;    -- null-safe equals
SELECT * FROM tbl WHERE NOT (col <=> 'val');  -- null-safe not-equals

postgresql.syntax:
SELECT * FROM users WHERE phone IS NULL;
SELECT * FROM users WHERE phone IS NOT NULL;
SELECT * FROM tbl WHERE a IS NOT DISTINCT FROM b;  -- null-safe equals
SELECT * FROM tbl WHERE a IS DISTINCT FROM b;       -- null-safe not-equals

sqlserver.syntax:
SELECT * FROM users WHERE phone IS NULL;
SELECT * FROM users WHERE phone IS NOT NULL;
-- Null-safe equals workaround:
SELECT * FROM tbl WHERE (a = b OR (a IS NULL AND b IS NULL));

oracle.syntax:
SELECT * FROM users WHERE phone IS NULL;
-- In Oracle, these are equivalent:
SELECT * FROM tbl WHERE col IS NULL;
SELECT * FROM tbl WHERE col = '';   -- '' IS NULL in Oracle

sqlite.syntax:
SELECT * FROM users WHERE phone IS NULL;
SELECT * FROM tbl WHERE a IS b;      -- null-safe equals
SELECT * FROM tbl WHERE a IS NOT b;  -- null-safe not-equals

mysql.syntax:
SELECT name, ROW_NUMBER() OVER (PARTITION BY dept_id ORDER BY salary DESC) AS rn
FROM employees;

-- Pre-8.0 workaround:
SELECT name, @rn := @rn + 1 AS rn FROM employees, (SELECT @rn := 0) r;

postgresql.syntax:
SELECT name, ROW_NUMBER() OVER (PARTITION BY dept_id ORDER BY salary DESC) AS rn
FROM employees;

-- Top-1 per group:
WITH ranked AS (
  SELECT *, ROW_NUMBER() OVER (PARTITION BY dept_id ORDER BY salary DESC) AS rn
  FROM employees
)
SELECT * FROM ranked WHERE rn = 1;

regex.syntax:
-- Varies significantly by engine.
-- PostgreSQL:
SELECT * FROM tbl WHERE col ~ '^[A-Z]';

-- MySQL:
SELECT * FROM tbl WHERE col REGEXP '^[A-Z]';

postgresql.syntax:
SELECT * FROM tbl WHERE col ~ '^[A-Z]';          -- case-sensitive
SELECT * FROM tbl WHERE col ~* '^[a-z]';         -- case-insensitive
SELECT regexp_match('foo123', '[0-9]+');          -- {123}
SELECT regexp_replace('foo123', '[0-9]+', '#');   -- 'foo#'
SELECT * FROM regexp_split_to_table('a,b,c', ',') AS t(val);

oracle.syntax:
SELECT * FROM tbl WHERE REGEXP_LIKE(col, '^[A-Z]');
SELECT * FROM tbl WHERE REGEXP_LIKE(col, '^[a-z]', 'i');
SELECT REGEXP_REPLACE('foo123', '[0-9]+', '#') FROM DUAL;  -- 'foo#'
SELECT REGEXP_SUBSTR('foo123bar', '[0-9]+')    FROM DUAL;  -- '123'

postgresql.syntax:
SELECT '2024-01-15'::date + INTERVAL '7 days';          -- 2024-01-22
SELECT NOW() - INTERVAL '1 month 2 days';
SELECT NOW() + INTERVAL '2 hours 30 minutes';
SELECT AGE('2024-06-01'::date, '2023-01-15'::date);    -- 1 year 4 mons 17 days

sqlserver.syntax:
SELECT DATEADD(day,    7,  '2024-01-15');   -- 2024-01-22
SELECT DATEADD(month, -1, '2024-01-15');   -- 2023-12-15
SELECT DATEADD(hour,  2,  GETDATE());
SELECT DATEADD(year,  1,  GETDATE());

oracle.syntax:
SELECT TO_CHAR(SYSDATE, 'YYYY-MM-DD')           FROM DUAL; -- '2024-03-15'
SELECT TO_CHAR(SYSDATE, 'DD/MM/YYYY')           FROM DUAL; -- '15/03/2024'
SELECT TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS') FROM DUAL;
SELECT TO_CHAR(SYSDATE, 'Day, Month DD YYYY')    FROM DUAL;

primary key.syntax:
CREATE TABLE users (
  id   INT PRIMARY KEY,
  name TEXT NOT NULL
);

-- Or as a named table constraint:
CREATE TABLE users (
  id   INT,
  name TEXT,
  CONSTRAINT pk_users PRIMARY KEY (id)
);

mysql.syntax:
CREATE TABLE users (
  id   INT AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(100) NOT NULL
) ENGINE=InnoDB;

-- Composite:
CREATE TABLE order_items (
  order_id INT,
  item_id  INT,
  PRIMARY KEY (order_id, item_id)
);

postgresql.syntax:
-- Modern (PG 10+):
CREATE TABLE users (
  id   INT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  name TEXT NOT NULL
);

-- Legacy SERIAL style:
CREATE TABLE users (
  id   SERIAL PRIMARY KEY,
  name TEXT NOT NULL
);

sqlserver.syntax:
CREATE TABLE users (
  id   INT IDENTITY(1,1) PRIMARY KEY,
  name NVARCHAR(100) NOT NULL
);

-- Non-clustered PK:
CREATE TABLE users (
  id INT PRIMARY KEY NONCLUSTERED,
  name NVARCHAR(100)
);

oracle.syntax:
-- Modern (12c+):
CREATE TABLE users (
  id   NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  name VARCHAR2(100) NOT NULL
);

-- Legacy sequence approach:
CREATE SEQUENCE user_seq START WITH 1 INCREMENT BY 1;
CREATE TABLE users (id NUMBER DEFAULT user_seq.NEXTVAL PRIMARY KEY, name VARCHAR2(100));

sqlite.syntax:
CREATE TABLE users (
  id   INTEGER PRIMARY KEY,      -- auto-increment via rowid alias
  name TEXT NOT NULL
);

-- AUTOINCREMENT prevents rowid reuse:
CREATE TABLE users (
  id   INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT
);

mysql.syntax:
CREATE TABLE orders (
  id          INT AUTO_INCREMENT PRIMARY KEY,
  customer_id INT,
  FOREIGN KEY (customer_id) REFERENCES customers(id)
    ON DELETE CASCADE
    ON UPDATE RESTRICT
) ENGINE=InnoDB;

-- Disable FK checks for bulk loads:
SET FOREIGN_KEY_CHECKS = 0;

postgresql.syntax:
CREATE TABLE orders (
  id          SERIAL PRIMARY KEY,
  customer_id INT REFERENCES customers(id) ON DELETE CASCADE
);

-- Deferrable constraint:
ALTER TABLE orders ADD CONSTRAINT fk_customer
  FOREIGN KEY (customer_id) REFERENCES customers(id)
  DEFERRABLE INITIALLY DEFERRED;

sqlserver.syntax:
CREATE TABLE orders (
  id          INT IDENTITY PRIMARY KEY,
  customer_id INT,
  CONSTRAINT fk_orders_customer
    FOREIGN KEY (customer_id) REFERENCES customers(id)
    ON DELETE CASCADE
);

-- Disable for bulk load:
ALTER TABLE orders NOCHECK CONSTRAINT fk_orders_customer;

oracle.syntax:
CREATE TABLE orders (
  id          NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  customer_id NUMBER,
  CONSTRAINT fk_orders_customer
    FOREIGN KEY (customer_id) REFERENCES customers(id)
    ON DELETE CASCADE
);

-- Recommended: index the FK column manually
CREATE INDEX idx_orders_cust ON orders(customer_id);

sqlite.syntax:
-- REQUIRED: enable FK enforcement first
PRAGMA foreign_keys = ON;

CREATE TABLE orders (
  id          INTEGER PRIMARY KEY,
  customer_id INTEGER REFERENCES customers(id) ON DELETE CASCADE
);

mysql.syntax:
CREATE TABLE employees (
  id     INT PRIMARY KEY,
  salary DECIMAL(10,2),
  status VARCHAR(20),
  CONSTRAINT chk_salary CHECK (salary > 0),
  CONSTRAINT chk_status CHECK (status IN ('active', 'inactive', 'pending'))
);

-- Add to existing table:
ALTER TABLE employees ADD CONSTRAINT chk_age CHECK (age >= 18);

postgresql.syntax:
CREATE TABLE employees (
  id     SERIAL PRIMARY KEY,
  salary NUMERIC CHECK (salary > 0),
  status TEXT   CHECK (status IN ('active', 'inactive', 'pending'))
);

-- Add without scanning existing rows:
ALTER TABLE employees
  ADD CONSTRAINT chk_salary CHECK (salary > 0) NOT VALID;
ALTER TABLE employees VALIDATE CONSTRAINT chk_salary;

sqlserver.syntax:
CREATE TABLE employees (
  id     INT IDENTITY PRIMARY KEY,
  salary DECIMAL(10,2) CHECK (salary > 0),
  status NVARCHAR(20)  CHECK (status IN ('active','inactive','pending'))
);

-- Add without checking existing rows:
ALTER TABLE employees
  WITH NOCHECK ADD CONSTRAINT chk_salary CHECK (salary > 0);

oracle.syntax:
CREATE TABLE employees (
  id     NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  salary NUMBER       CONSTRAINT chk_salary CHECK (salary > 0),
  status VARCHAR2(20) CONSTRAINT chk_status CHECK (status IN ('active','inactive','pending'))
);

ALTER TABLE employees ADD CONSTRAINT chk_age CHECK (age >= 18) ENABLE NOVALIDATE;

sqlite.syntax:
CREATE TABLE employees (
  id     INTEGER PRIMARY KEY,
  salary REAL    CHECK (salary > 0),
  status TEXT    CHECK (status IN ('active', 'inactive', 'pending'))
);

-- SQLite allows subqueries in CHECK (unusual):
CREATE TABLE items (
  cat_id INT CHECK (cat_id IN (SELECT id FROM categories))
);

unique constraint.syntax:
CREATE TABLE users (
  id    INT PRIMARY KEY,
  email TEXT UNIQUE,
  username TEXT,
  CONSTRAINT uq_username UNIQUE (username)
);

mysql.syntax:
CREATE TABLE users (
  id       INT AUTO_INCREMENT PRIMARY KEY,
  email    VARCHAR(255) UNIQUE,
  username VARCHAR(50)
);

-- Composite unique:
ALTER TABLE users ADD CONSTRAINT uq_name_email UNIQUE (username, email);

-- Drop:
ALTER TABLE users DROP INDEX uq_name_email;

postgresql.syntax:
CREATE TABLE users (
  id    SERIAL PRIMARY KEY,
  email TEXT UNIQUE
);

-- PG 15+: treat NULL as equal (only one NULL allowed):
CREATE UNIQUE INDEX ON users (email) NULLS NOT DISTINCT;

-- Composite:
ALTER TABLE users ADD CONSTRAINT uq_name UNIQUE (first_name, last_name);

sqlserver.syntax:
CREATE TABLE users (
  id    INT IDENTITY PRIMARY KEY,
  email NVARCHAR(255) UNIQUE
);

-- Allow multiple NULLs via filtered index:
CREATE UNIQUE INDEX uq_email ON users(email) WHERE email IS NOT NULL;

-- Drop:
ALTER TABLE users DROP CONSTRAINT uq_users_email;

oracle.syntax:
CREATE TABLE users (
  id    NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  email VARCHAR2(255) UNIQUE
);

-- Named constraint:
ALTER TABLE users ADD CONSTRAINT uq_email UNIQUE (email);

-- Disable without dropping:
ALTER TABLE users DISABLE CONSTRAINT uq_email;

sqlite.syntax:
CREATE TABLE users (
  id    INTEGER PRIMARY KEY,
  email TEXT UNIQUE
);

-- Composite:
CREATE TABLE memberships (
  user_id INT,
  group_id INT,
  UNIQUE (user_id, group_id)
);

default value.syntax:
CREATE TABLE events (
  id         INT PRIMARY KEY,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  status     VARCHAR(20) DEFAULT 'pending'
);

mysql.syntax:
CREATE TABLE events (
  id         INT AUTO_INCREMENT PRIMARY KEY,
  status     VARCHAR(20)  DEFAULT 'pending',
  score      INT          DEFAULT 0,
  created_at DATETIME     DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME     DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

-- Expression default (8.0.13+):
CREATE TABLE items (price DECIMAL(10,2), tax DECIMAL(10,2) DEFAULT (price * 0.1));

postgresql.syntax:
CREATE TABLE events (
  id         SERIAL PRIMARY KEY,
  status     TEXT        DEFAULT 'pending',
  created_at TIMESTAMPTZ DEFAULT NOW(),
  token      UUID        DEFAULT gen_random_uuid()
);

ALTER TABLE events ALTER COLUMN status SET DEFAULT 'active';
ALTER TABLE events ALTER COLUMN status DROP DEFAULT;

sqlserver.syntax:
CREATE TABLE events (
  id         INT IDENTITY PRIMARY KEY,
  status     NVARCHAR(20) CONSTRAINT df_status DEFAULT 'pending',
  created_at DATETIME     CONSTRAINT df_created DEFAULT GETDATE(),
  token      UNIQUEIDENTIFIER CONSTRAINT df_token DEFAULT NEWID()
);

-- Explicit default in INSERT:
INSERT INTO events (status, created_at) VALUES (DEFAULT, DEFAULT);

-- Drop a named default:
ALTER TABLE events DROP CONSTRAINT df_status;

oracle.syntax:
CREATE TABLE events (
  id         NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  status     VARCHAR2(20)  DEFAULT 'pending',
  created_at TIMESTAMP     DEFAULT SYSTIMESTAMP,
  token      RAW(16)       DEFAULT SYS_GUID()
);

-- 12c+: default even when NULL is explicitly inserted:
CREATE TABLE items (qty NUMBER DEFAULT ON NULL 1);

sqlite.syntax:
CREATE TABLE events (
  id         INTEGER PRIMARY KEY,
  status     TEXT     DEFAULT 'pending',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  score      INTEGER  DEFAULT 0
);

not null.syntax:
CREATE TABLE users (
  id    INT NOT NULL PRIMARY KEY,
  email TEXT NOT NULL,
  bio   TEXT NULL  -- explicit NULL (optional)
);

mysql.syntax:
CREATE TABLE users (
  id    INT          NOT NULL AUTO_INCREMENT PRIMARY KEY,
  email VARCHAR(255) NOT NULL,
  bio   TEXT         NULL
);

-- Enable strict mode (recommended):
SET sql_mode = 'STRICT_ALL_TABLES';

-- Add NOT NULL to existing column:
ALTER TABLE users MODIFY COLUMN bio TEXT NOT NULL DEFAULT '';

postgresql.syntax:
CREATE TABLE users (
  id    SERIAL PRIMARY KEY,
  email TEXT NOT NULL,
  bio   TEXT
);

-- Add NOT NULL to existing column:
ALTER TABLE users ALTER COLUMN email SET NOT NULL;

-- Remove NOT NULL:
ALTER TABLE users ALTER COLUMN email DROP NOT NULL;

sqlserver.syntax:
CREATE TABLE users (
  id    INT           NOT NULL IDENTITY PRIMARY KEY,
  email NVARCHAR(255) NOT NULL,
  bio   NVARCHAR(MAX) NULL
);

-- Change nullability:
ALTER TABLE users ALTER COLUMN email NVARCHAR(255) NOT NULL;

-- If NULLs exist, update first:
UPDATE users SET email = '' WHERE email IS NULL;
ALTER TABLE users ALTER COLUMN email NVARCHAR(255) NOT NULL;

oracle.syntax:
CREATE TABLE users (
  id    NUMBER        NOT NULL PRIMARY KEY,
  email VARCHAR2(255) NOT NULL,
  bio   VARCHAR2(4000)
);

-- Change nullability:
ALTER TABLE users MODIFY email VARCHAR2(255) NOT NULL;
ALTER TABLE users MODIFY bio   VARCHAR2(4000) NULL;

sqlite.syntax:
CREATE TABLE users (
  id    INTEGER PRIMARY KEY,  -- implicitly NOT NULL
  email TEXT NOT NULL,
  bio   TEXT                  -- nullable
);

in / not in.syntax:
SELECT * FROM orders WHERE status IN ('pending', 'processing', 'shipped');

SELECT * FROM orders WHERE customer_id NOT IN (
  SELECT id FROM customers WHERE region = 'EU'
);

mysql.syntax:
SELECT * FROM orders WHERE status IN ('pending', 'processing');
SELECT * FROM orders WHERE id NOT IN (1, 2, 3);

-- Safer alternative when NULLs possible:
SELECT * FROM orders o
WHERE NOT EXISTS (
  SELECT 1 FROM blacklist b WHERE b.id = o.customer_id
);

postgresql.syntax:
SELECT * FROM orders WHERE status IN ('pending', 'processing');

-- Array alternative (often faster for large lists):
SELECT * FROM orders WHERE status = ANY(ARRAY['pending', 'processing']);

-- NOT IN NULL trap workaround:
SELECT * FROM orders o
WHERE NOT EXISTS (SELECT 1 FROM blacklist b WHERE b.id = o.customer_id);

sqlserver.syntax:
SELECT * FROM orders WHERE status IN ('pending', 'processing', 'shipped');
SELECT * FROM orders WHERE id NOT IN (1, 2, 3);

-- For large lists, use a table:
DECLARE @ids TABLE (id INT);
INSERT INTO @ids VALUES (1),(2),(3);
SELECT * FROM orders WHERE id IN (SELECT id FROM @ids);

oracle.syntax:
SELECT * FROM orders WHERE status IN ('pending', 'processing');

-- Hard limit: max 1000 items in IN list:
-- SELECT * FROM t WHERE id IN (1, 2, ..., 1001);  -- ORA-01795 error!

-- Workaround for large lists:
SELECT * FROM orders WHERE id IN (SELECT id FROM my_id_list_table);

sqlite.syntax:
SELECT * FROM orders WHERE status IN ('pending', 'processing');
SELECT * FROM orders WHERE id NOT IN (1, 2, 3);

-- NULL trap demonstration:
SELECT * FROM t WHERE x NOT IN (1, NULL);  -- always returns 0 rows!

between.syntax:
SELECT * FROM orders
WHERE amount BETWEEN 100 AND 500;

SELECT * FROM events
WHERE event_date BETWEEN '2024-01-01' AND '2024-03-31';

mysql.syntax:
SELECT * FROM orders WHERE amount BETWEEN 100 AND 500;
SELECT * FROM orders WHERE amount NOT BETWEEN 100 AND 500;

-- Date range (DATE type — safe):
SELECT * FROM events WHERE event_date BETWEEN '2024-01-01' AND '2024-01-31';

-- DATETIME — use < instead to avoid midnight trap:
SELECT * FROM events WHERE created_at >= '2024-01-01' AND created_at < '2024-02-01';

postgresql.syntax:
SELECT * FROM orders WHERE amount BETWEEN 100 AND 500;
SELECT * FROM orders WHERE amount NOT BETWEEN 100 AND 500;

-- SYMMETRIC: order doesn't matter
SELECT * FROM orders WHERE amount BETWEEN SYMMETRIC 500 AND 100;  -- same as 100..500

sqlserver.syntax:
SELECT * FROM orders WHERE amount BETWEEN 100 AND 500;
SELECT * FROM orders WHERE amount NOT BETWEEN 100 AND 500;

-- Safe datetime range (no midnight trap):
SELECT * FROM orders
WHERE created_at >= '2024-01-01' AND created_at < '2024-02-01';

oracle.syntax:
SELECT * FROM orders WHERE amount BETWEEN 100 AND 500;

-- Oracle DATE includes time — use TRUNC to strip it:
SELECT * FROM events
WHERE event_date BETWEEN TRUNC(SYSDATE) AND TRUNC(SYSDATE) + 1;

sqlite.syntax:
SELECT * FROM orders WHERE amount BETWEEN 100 AND 500;

-- Text dates work correctly in ISO 8601 format:
SELECT * FROM events
WHERE event_date BETWEEN '2024-01-01' AND '2024-03-31';

postgresql.syntax:
SELECT * FROM tbl ORDER BY id LIMIT 10;
SELECT * FROM tbl ORDER BY id LIMIT 10 OFFSET 20;

-- Standard SQL:
SELECT * FROM tbl ORDER BY id
OFFSET 20 ROWS FETCH NEXT 10 ROWS ONLY;

-- No limit:
SELECT * FROM tbl ORDER BY id LIMIT ALL OFFSET 5;

sqlserver.syntax:
-- Modern standard:
SELECT * FROM tbl ORDER BY id
OFFSET 20 ROWS FETCH NEXT 10 ROWS ONLY;

-- Legacy TOP (all versions):
SELECT TOP 10 * FROM tbl ORDER BY id;
SELECT TOP 10 PERCENT * FROM tbl ORDER BY id;
SELECT TOP 10 WITH TIES * FROM tbl ORDER BY id;

oracle.syntax:
-- Modern (12c+):
SELECT * FROM tbl ORDER BY id
FETCH FIRST 10 ROWS ONLY;

SELECT * FROM tbl ORDER BY id
OFFSET 20 ROWS FETCH NEXT 10 ROWS ONLY;

-- Legacy ROWNUM (pre-12c — must wrap in subquery):
SELECT * FROM (
  SELECT * FROM tbl ORDER BY id
) WHERE ROWNUM <= 10;

sqlite.syntax:
SELECT * FROM tbl ORDER BY id LIMIT 10;
SELECT * FROM tbl ORDER BY id LIMIT 10 OFFSET 20;

-- Offset without row cap:
SELECT * FROM tbl ORDER BY id LIMIT -1 OFFSET 20;

sqlserver.syntax:
SELECT name, dept, salary,
  FIRST_VALUE(salary) OVER (PARTITION BY dept ORDER BY salary DESC) AS top_salary,
  LAST_VALUE(salary)  OVER (
    PARTITION BY dept ORDER BY salary DESC
    ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING
  ) AS bottom_salary
FROM employees;

-- SQL Server 2022+:
SELECT FIRST_VALUE(salary) IGNORE NULLS OVER (ORDER BY hire_date) FROM employees;

oracle.syntax:
SELECT name, score,
  NTILE(4) OVER (ORDER BY score DESC) AS quartile
FROM students;

sqlite.syntax:
SELECT name, score,
  NTILE(4) OVER (ORDER BY score DESC) AS quartile
FROM students;

json extract.syntax:
-- MySQL / SQLite path syntax:
SELECT JSON_EXTRACT(data, '$.name') AS name
FROM users;

-- PostgreSQL operator shorthand:
SELECT data->>'name' AS name
FROM users;

-- SQL Server / Oracle:
SELECT JSON_VALUE(data, '$.name') AS name
FROM users;

postgresql.syntax:
-- Single key, JSON result:
SELECT data->'name'            AS name_json
FROM users;

-- Single key, text result:
SELECT data->>'name'           AS name_text
FROM users;

-- Nested path, JSON result:
SELECT data#>'{address,city}'  AS city_json
FROM users;

-- Nested path, text result:
SELECT data#>>'{address,city}' AS city_text
FROM users;

-- Function form:
SELECT jsonb_extract_path_text(data, 'address', 'city') AS city
FROM users;

-- Key extraction:
SELECT data->'name'             AS name_json,
       data->>'name'            AS name_text
FROM users;

-- Array index:
SELECT data->'tags'->0          AS first_tag_json,
       data->'tags'->>0         AS first_tag_text
FROM posts;

-- Nested path (path array):
SELECT data#>'{address,city}'   AS city_json,
       data#>>'{address,city}'  AS city_text
FROM users;

-- jsonb containment / existence:
SELECT * FROM users WHERE data @> '{"role":"admin"}';
SELECT * FROM users WHERE data ? 'email';
SELECT * FROM users WHERE data ?| ARRAY['admin','superuser'];

sequence / autoincrement.syntax:
-- Standard SQL (PostgreSQL 10+, SQL Server 2012+, Oracle 12c+):
CREATE TABLE orders (
    id INTEGER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    amount DECIMAL(10,2)
);

-- MySQL:
CREATE TABLE orders (
    id INT AUTO_INCREMENT PRIMARY KEY,
    amount DECIMAL(10,2)
);

mysql.syntax:
-- Basic AUTO_INCREMENT:
CREATE TABLE orders (
    id    INT AUTO_INCREMENT PRIMARY KEY,
    total DECIMAL(10,2)
);

-- Custom start value:
CREATE TABLE orders (
    id    INT AUTO_INCREMENT PRIMARY KEY,
    total DECIMAL(10,2)
) AUTO_INCREMENT = 1000;

-- Reset/set current value:
ALTER TABLE orders AUTO_INCREMENT = 5000;

-- Get last inserted ID:
SELECT LAST_INSERT_ID();

postgresql.syntax:
-- SQL standard (recommended, PG 10+):
CREATE TABLE orders (
    id    INTEGER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    total DECIMAL(10,2)
);

-- GENERATED BY DEFAULT (allows override):
CREATE TABLE orders (
    id    INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    total DECIMAL(10,2)
);

-- Legacy SERIAL (still common):
CREATE TABLE orders (
    id    SERIAL PRIMARY KEY,
    total DECIMAL(10,2)
);

-- Standalone sequence:
CREATE SEQUENCE order_id_seq START 1000 INCREMENT 1;
SELECT nextval('order_id_seq');
SELECT currval('order_id_seq');

sqlserver.syntax:
-- IDENTITY column:
CREATE TABLE orders (
    id    INT IDENTITY(1,1) PRIMARY KEY,
    total DECIMAL(10,2)
);

-- Get last inserted ID:
SELECT SCOPE_IDENTITY() AS new_id;

-- OUTPUT clause alternative:
INSERT INTO orders (total)
OUTPUT INSERTED.id
VALUES (99.99);

-- Standalone SEQUENCE (2012+):
CREATE SEQUENCE order_seq START WITH 1000 INCREMENT BY 1;
SELECT NEXT VALUE FOR order_seq;

oracle.syntax:
-- Standard identity column (12c+):
CREATE TABLE orders (
    id    NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    total NUMBER(10,2)
);

-- GENERATED BY DEFAULT (allows override):
CREATE TABLE orders (
    id    NUMBER GENERATED BY DEFAULT AS IDENTITY START WITH 1000 PRIMARY KEY,
    total NUMBER(10,2)
);

-- Legacy sequence approach (pre-12c):
CREATE SEQUENCE order_id_seq START WITH 1 INCREMENT BY 1 NOCACHE;

INSERT INTO orders (id, total)
VALUES (order_id_seq.NEXTVAL, 99.99);

SELECT order_id_seq.CURRVAL FROM dual;

sqlite.syntax:
-- INTEGER PRIMARY KEY (implicit autoincrement, recommended):
CREATE TABLE orders (
    id    INTEGER PRIMARY KEY,
    total REAL
);

-- AUTOINCREMENT keyword (strict no-reuse guarantee):
CREATE TABLE orders (
    id    INTEGER PRIMARY KEY AUTOINCREMENT,
    total REAL
);

-- Get last inserted rowid:
SELECT last_insert_rowid();

nullif.syntax:
-- Avoid division by zero:
SELECT total_revenue / NULLIF(total_orders, 0) AS avg_order_value
FROM sales_summary;

-- Convert empty string to NULL:
SELECT NULLIF(email, '') AS email
FROM users;

postgresql.syntax:
-- Division-by-zero guard:
SELECT revenue / NULLIF(costs, 0) AS margin
FROM financials;

-- Combine with COALESCE for default value:
SELECT COALESCE(NULLIF(nickname, ''), full_name) AS display_name
FROM users;

-- Date comparison:
SELECT NULLIF(end_date, '9999-12-31'::date) AS actual_end
FROM contracts;

sqlite.syntax:
-- Division-by-zero guard:
SELECT price / NULLIF(quantity, 0) AS unit_cost
FROM inventory;

-- Convert sentinel value to NULL:
SELECT NULLIF(category, 'UNKNOWN') AS category
FROM products;

greatest / least.syntax:
-- Clamp a value between a min and max:
SELECT GREATEST(LEAST(score, 100), 0) AS clamped_score
FROM results;

-- Latest of two dates:
SELECT GREATEST(start_date, effective_date) AS use_date
FROM contracts;

sqlserver.syntax:
-- SQL Server 2022+:
SELECT GREATEST(q1_sales, q2_sales, q3_sales) AS peak_quarter
FROM quarterly_results;

SELECT LEAST(ship_date, delivery_date) AS earlier_date
FROM shipments;

-- Workaround for SQL Server 2019 and earlier (2 values):
SELECT IIF(q1 > q2, q1, q2) AS greatest_2
FROM quarterly_results;

-- Workaround for SQL Server 2019 and earlier (3+ values via VALUES):
SELECT (SELECT MAX(v) FROM (VALUES (q1), (q2), (q3)) AS t(v)) AS peak
FROM quarterly_results;

oracle.syntax:
SELECT GREATEST(q1_sales, q2_sales, q3_sales, q4_sales) AS peak_quarter
FROM quarterly_results;

-- Clamp:
SELECT GREATEST(LEAST(score, 100), 0) AS clamped_score
FROM exam_results;

-- NULL propagation:
SELECT GREATEST(1, NULL, 3) FROM dual; -- Returns NULL

-- NVL workaround when NULLs must be handled:
SELECT GREATEST(NVL(col1, 0), NVL(col2, 0)) AS safe_greatest
FROM t;

generated columns.syntax:
-- SQL standard (MySQL 5.7+, PostgreSQL 12+):
CREATE TABLE products (
    price     DECIMAL(10,2),
    tax_rate  DECIMAL(4,3),
    total     DECIMAL(10,2) GENERATED ALWAYS AS (price * (1 + tax_rate)) STORED
);

mysql.syntax:
CREATE TABLE products (
    price      DECIMAL(10,2),
    quantity   INT,
    subtotal   DECIMAL(10,2) GENERATED ALWAYS AS (price * quantity) VIRTUAL,
    subtotal_s DECIMAL(10,2) GENERATED ALWAYS AS (price * quantity) STORED
);

-- Index on STORED generated column:
CREATE INDEX idx_subtotal ON products (subtotal_s);

-- Add generated column to existing table:
ALTER TABLE products
    ADD COLUMN tax DECIMAL(10,2) GENERATED ALWAYS AS (price * 0.1) STORED;

postgresql.syntax:
CREATE TABLE products (
    price    NUMERIC(10,2),
    quantity INTEGER,
    subtotal NUMERIC(10,2) GENERATED ALWAYS AS (price * quantity) STORED
);

-- Index on generated column (works like any other column):
CREATE INDEX idx_subtotal ON products (subtotal);

-- Cannot INSERT/UPDATE a generated column directly:
INSERT INTO products (price, quantity) VALUES (9.99, 5);
-- subtotal is automatically 49.95

sqlserver.syntax:
CREATE TABLE products (
    price      DECIMAL(10,2),
    quantity   INT,
    subtotal   AS (price * quantity),              -- virtual
    subtotal_p AS (price * quantity) PERSISTED     -- stored
);

-- Index requires PERSISTED for non-simple expressions:
CREATE INDEX idx_subtotal ON products (subtotal_p);

-- Add to existing table:
ALTER TABLE products
    ADD tax AS (price * 0.1) PERSISTED;

oracle.syntax:
CREATE TABLE products (
    price    NUMBER(10,2),
    quantity NUMBER,
    subtotal NUMBER(10,2) GENERATED ALWAYS AS (price * quantity) VIRTUAL
);

-- Index on virtual column:
CREATE INDEX idx_subtotal ON products (subtotal);

-- Simplified syntax (VIRTUAL is default/only option):
CREATE TABLE products (
    price    NUMBER(10,2),
    quantity NUMBER,
    subtotal AS (price * quantity)
);

sqlite.syntax:
CREATE TABLE products (
    price    REAL,
    quantity INTEGER,
    subtotal REAL GENERATED ALWAYS AS (price * quantity) VIRTUAL,
    subtotal_s REAL GENERATED ALWAYS AS (price * quantity) STORED
);

-- Shorthand (AS without GENERATED ALWAYS):
CREATE TABLE products (
    price    REAL,
    quantity INTEGER,
    subtotal REAL AS (price * quantity)
);

mysql.syntax:
-- Workaround: populate a summary table via event:
CREATE TABLE monthly_sales_cache (
    month DATE PRIMARY KEY,
    total DECIMAL(15,2)
);

CREATE EVENT refresh_monthly_sales
    ON SCHEDULE EVERY 1 HOUR
    DO
    BEGIN
        TRUNCATE TABLE monthly_sales_cache;
        INSERT INTO monthly_sales_cache
        SELECT DATE_FORMAT(order_date,'%Y-%m-01'), SUM(amount)
        FROM orders
        GROUP BY 1;
    END;

postgresql.syntax:
CREATE MATERIALIZED VIEW monthly_sales AS
SELECT date_trunc('month', order_date) AS month,
       SUM(amount)                      AS total
FROM orders
GROUP BY 1
WITH DATA;  -- populate immediately (default)

-- Without initial data:
CREATE MATERIALIZED VIEW monthly_sales AS ... WITH NO DATA;

-- Refresh (blocking):
REFRESH MATERIALIZED VIEW monthly_sales;

-- Refresh without locking reads (requires unique index):
CREATE UNIQUE INDEX ON monthly_sales (month);
REFRESH MATERIALIZED VIEW CONCURRENTLY monthly_sales;

-- Drop:
DROP MATERIALIZED VIEW monthly_sales;

sqlite.syntax:
-- Workaround: populate a summary table:
CREATE TABLE monthly_sales_cache (
    month TEXT PRIMARY KEY,
    total REAL
);

-- Refresh manually:
DELETE FROM monthly_sales_cache;
INSERT INTO monthly_sales_cache
SELECT strftime('%Y-%m', order_date), SUM(amount)
FROM orders
GROUP BY strftime('%Y-%m', order_date);

temporary tables.syntax:
-- Standard SQL:
CREATE TEMPORARY TABLE temp_results (
    id      INT,
    result  VARCHAR(255)
);

INSERT INTO temp_results SELECT id, compute(val) FROM source;
SELECT * FROM temp_results;

mysql.syntax:
CREATE TEMPORARY TABLE tmp_active_users (
    id       INT,
    username VARCHAR(100)
);

INSERT INTO tmp_active_users
SELECT id, username FROM users WHERE active = 1;

SELECT * FROM tmp_active_users;

-- Dropped automatically at session end;
-- or drop explicitly:
DROP TEMPORARY TABLE tmp_active_users;

postgresql.syntax:
-- Session-scoped (default):
CREATE TEMP TABLE tmp_active_users (
    id       INT,
    username TEXT
);

-- Transaction-scoped (dropped on COMMIT/ROLLBACK):
CREATE TEMP TABLE tmp_work (
    val INT
) ON COMMIT DROP;

-- Keep structure, truncate on commit:
CREATE TEMP TABLE tmp_batch (
    val INT
) ON COMMIT DELETE ROWS;

-- From query:
CREATE TEMP TABLE tmp_summary AS
SELECT dept, SUM(salary) FROM employees GROUP BY dept;

sqlserver.syntax:
-- Local temp table (session-private):
CREATE TABLE #tmp_active_users (
    id       INT,
    username NVARCHAR(100)
);

INSERT INTO #tmp_active_users
SELECT id, username FROM users WHERE active = 1;

SELECT * FROM #tmp_active_users;
DROP TABLE IF EXISTS #tmp_active_users;

-- Global temp table (cross-session):
CREATE TABLE ##shared_work (
    val INT
);

-- Table variable (alternative, no DDL needed):
DECLARE @results TABLE (id INT, val NVARCHAR(100));
INSERT INTO @results VALUES (1,'a');

oracle.syntax:
-- Global temporary table (structure persists, data is private):
CREATE GLOBAL TEMPORARY TABLE tmp_active_users (
    id       NUMBER,
    username VARCHAR2(100)
) ON COMMIT PRESERVE ROWS;  -- session-scoped data

-- Transaction-scoped data:
CREATE GLOBAL TEMPORARY TABLE tmp_batch (
    val NUMBER
) ON COMMIT DELETE ROWS;    -- default

-- Private temporary table (18c+, session-scoped structure):
CREATE PRIVATE TEMPORARY TABLE ora$ptt_work (
    id NUMBER
) ON COMMIT DROP DEFINITION;

INSERT INTO tmp_active_users SELECT id, username FROM users WHERE active=1;
SELECT * FROM tmp_active_users;

sqlite.syntax:
CREATE TEMPORARY TABLE tmp_active_users (
    id       INTEGER,
    username TEXT
);

INSERT INTO tmp_active_users
SELECT id, username FROM users WHERE active = 1;

SELECT * FROM tmp_active_users;

-- Explicit drop:
DROP TABLE IF EXISTS tmp_active_users;

-- In-memory temp table (default connection is :memory:):
-- All tables are implicitly temp when connection is :memory:

any / all.syntax:
-- ANY: true if salary > any value returned
SELECT name FROM employees
WHERE salary > ANY (
    SELECT salary FROM employees WHERE dept = 'Sales'
);

-- ALL: true only if salary > every value returned
SELECT name FROM employees
WHERE salary > ALL (
    SELECT salary FROM employees WHERE dept = 'Interns'
);

mysql.syntax:
-- ANY (true if any value matches):
SELECT name FROM employees
WHERE salary > ANY (SELECT salary FROM employees WHERE dept = 'Sales');

-- ALL (true if all values match):
SELECT name FROM employees
WHERE salary > ALL (SELECT salary FROM employees WHERE dept = 'Interns');

-- = ANY is equivalent to IN:
SELECT * FROM products
WHERE category_id = ANY (SELECT id FROM categories WHERE active = 1);
-- same as: WHERE category_id IN (SELECT id FROM categories WHERE active = 1)

-- <> ALL is equivalent to NOT IN:
SELECT * FROM orders
WHERE status <> ALL (SELECT status FROM cancelled_statuses);

postgresql.syntax:
-- Subquery form:
SELECT name FROM employees
WHERE salary > ANY (SELECT salary FROM employees WHERE dept = 'Sales');

-- Array form (PostgreSQL extension):
SELECT * FROM products
WHERE category_id = ANY(ARRAY[1, 2, 3]);

SELECT * FROM orders
WHERE status <> ALL(ARRAY['cancelled', 'refunded']);

-- Useful for parameterized queries:
-- WHERE tag_id = ANY($1::int[])  (pass an array parameter)

sqlserver.syntax:
-- ANY with subquery:
SELECT name FROM employees
WHERE salary > ANY (SELECT salary FROM employees WHERE dept = 'Sales');

-- ALL with subquery:
SELECT name FROM employees
WHERE salary > ALL (SELECT salary FROM employees WHERE dept = 'Interns');

-- More common SQL Server idiom (equivalent):
SELECT name FROM employees
WHERE salary > (SELECT MIN(salary) FROM employees WHERE dept = 'Interns');
-- (MIN achieves the same as > ALL; MAX achieves the same as > ANY)

oracle.syntax:
-- ANY:
SELECT name FROM employees
WHERE salary > ANY (SELECT salary FROM employees WHERE dept = 'Sales');

-- ALL:
SELECT name FROM employees
WHERE salary > ALL (SELECT salary FROM employees WHERE dept = 'Interns');

-- Equivalent using aggregate:
SELECT name FROM employees
WHERE salary > (SELECT MAX(salary) FROM employees WHERE dept = 'Interns');
-- (MAX(x) = x > ALL subquery; MIN(x) = x > ANY subquery)

sqlite.syntax:
-- Instead of > ANY(subquery), use > MIN(...):
SELECT name FROM employees
WHERE salary > (SELECT MIN(salary) FROM employees WHERE dept = 'Sales');

-- Instead of > ALL(subquery), use > MAX(...):
SELECT name FROM employees
WHERE salary > (SELECT MAX(salary) FROM employees WHERE dept = 'Interns');

-- Instead of = ANY, use IN:
SELECT * FROM products
WHERE category_id IN (SELECT id FROM categories WHERE active = 1);

values clause.syntax:
-- Inline table of literal values:
SELECT *
FROM (VALUES (1, 'Alice'), (2, 'Bob'), (3, 'Carol')) AS t(id, name);

-- Multi-row INSERT:
INSERT INTO colors (id, name)
VALUES (1, 'red'), (2, 'green'), (3, 'blue');

sqlite.syntax:
-- Inline table:
SELECT *
FROM (VALUES (1, 'Alice'), (2, 'Bob')) AS t(id, name);

-- CTE with VALUES:
WITH priority(level, label) AS (
    VALUES (1,'low'),(2,'medium'),(3,'high')
)
SELECT * FROM priority;

-- Multi-row INSERT:
INSERT INTO colors (id, name)
VALUES (1,'red'),(2,'green'),(3,'blue');

mysql.syntax:
-- Workaround: generated column + index (NULLs not indexed):
ALTER TABLE users
    ADD COLUMN active_email VARCHAR(255)
        GENERATED ALWAYS AS (IF(active = 1, email, NULL)) VIRTUAL;

CREATE INDEX idx_active_email ON users (active_email);

-- Now a query for active users can use the index:
SELECT * FROM users WHERE active_email = 'alice@example.com';
-- This is equivalent to: WHERE active = 1 AND email = 'alice@example.com'

oracle.syntax:
-- Workaround: function-based index returning NULL for excluded rows:
-- Index only active users (active=1):
CREATE INDEX idx_active_users
    ON users (CASE WHEN active = 1 THEN email END);

-- Query must match the expression to use the index:
SELECT * FROM users
WHERE CASE WHEN active = 1 THEN email END = 'alice@example.com';

-- More practical: filter via NOT NULL expression:
CREATE INDEX idx_pending
    ON orders (CASE WHEN status = 'PENDING' THEN order_id END);

savepoint.syntax:
BEGIN;

INSERT INTO orders (customer_id, total) VALUES (1, 99.99);
SAVEPOINT after_order;

INSERT INTO order_items (order_id, product_id) VALUES (101, 9);
-- If this fails:
ROLLBACK TO SAVEPOINT after_order;

-- Order insert is still intact; continue or commit:
COMMIT;

mysql.syntax:
START TRANSACTION;

INSERT INTO orders (customer_id, total) VALUES (1, 99.99);
SAVEPOINT sp1;

INSERT INTO order_items (order_id, product_id) VALUES (101, 9);

-- Partial rollback:
ROLLBACK TO SAVEPOINT sp1;
-- order_items INSERT is undone; orders INSERT remains

-- Release savepoint (optional, removes the savepoint marker):
RELEASE SAVEPOINT sp1;

COMMIT;

postgresql.syntax:
BEGIN;

INSERT INTO orders (customer_id, total) VALUES (1, 99.99);
SAVEPOINT after_order;

INSERT INTO order_items (order_id, product_id) VALUES (101, 9);
-- Suppose this raises an error:
ROLLBACK TO SAVEPOINT after_order;
-- Transaction is now in a clean state; the error is cleared

INSERT INTO order_items (order_id, product_id) VALUES (101, 10);
-- Try a different item

COMMIT;

-- Release (optional, frees the savepoint name):
RELEASE SAVEPOINT after_order;

sqlserver.syntax:
BEGIN TRANSACTION;

INSERT INTO orders (customer_id, total) VALUES (1, 99.99);
SAVE TRANSACTION after_order;  -- SQL Server uses SAVE TRANSACTION

INSERT INTO order_items (order_id, product_id) VALUES (101, 9);

-- Partial rollback:
ROLLBACK TRANSACTION after_order;
-- order_items insert is undone; orders insert remains

-- Note: can also use shorthand:
-- SAVE TRAN sp1 / ROLLBACK TRAN sp1

COMMIT TRANSACTION;

oracle.syntax:
-- No explicit BEGIN in Oracle:
INSERT INTO orders (customer_id, total) VALUES (1, 99.99);
SAVEPOINT after_order;

INSERT INTO order_items (order_id, product_id) VALUES (101, 9);

-- Partial rollback:
ROLLBACK TO SAVEPOINT after_order;
-- order_items insert rolled back; orders insert intact

COMMIT;
-- Savepoint is implicitly released on COMMIT

sqlite.syntax:
BEGIN;

INSERT INTO orders (customer_id, total) VALUES (1, 99.99);
SAVEPOINT after_order;

INSERT INTO order_items (order_id, product_id) VALUES (101, 9);

-- Partial rollback:
ROLLBACK TO after_order;

-- Release (removes the savepoint marker, merges into outer transaction):
RELEASE after_order;

COMMIT;

-- SQLite SAVEPOINT can also nest:
SAVEPOINT outer;
    INSERT INTO t VALUES (1);
    SAVEPOINT inner;
        INSERT INTO t VALUES (2);
    RELEASE inner;  -- commits inner work into outer
ROLLBACK TO outer;  -- undoes everything including inner

-- sqlite3 CLI import:
-- .mode csv
-- .import /data/orders.csv orders

-- Or with headers (sqlite3 3.32+):
-- .import --csv --skip 1 /data/orders.csv orders

-- Programmatic bulk insert (wrap in transaction for speed):
-- BEGIN;
-- INSERT INTO orders VALUES (1, 101, 99.99, '2024-01-15');
-- INSERT INTO orders VALUES (2, 102, 49.50, '2024-01-16');
-- ... (thousands of rows)
-- COMMIT;
-- Without the transaction wrapper each INSERT is its own fsync.

iif / decode / conditional shorthand.syntax:
-- SQL Server / Access:
SELECT IIF(salary > 50000, 'Senior', 'Junior') AS grade
FROM employees;

-- Oracle:
SELECT DECODE(status, 'A', 'Active', 'I', 'Inactive', 'Unknown') AS label
FROM accounts;

-- MySQL:
SELECT IF(salary > 50000, 'Senior', 'Junior') AS grade
FROM employees;

sqlserver.syntax:
-- IIF (SQL Server 2012+):
SELECT IIF(salary > 50000, 'Senior', 'Junior') AS grade
FROM employees;

-- Nested IIF:
SELECT IIF(score >= 90, 'A', IIF(score >= 80, 'B', IIF(score >= 70, 'C', 'F'))) AS grade
FROM students;

-- CHOOSE (index into list):
SELECT CHOOSE(priority, 'Low', 'Medium', 'High', 'Critical') AS priority_label
FROM tickets;
-- CHOOSE(1,...) = 'Low', CHOOSE(2,...) = 'Medium', etc.

-- ISNULL (NULL check shorthand):
SELECT ISNULL(nickname, full_name) AS display_name
FROM users;

oracle.syntax:
-- DECODE (Oracle proprietary):
SELECT DECODE(status, 'A', 'Active', 'I', 'Inactive', 'Unknown') AS label
FROM accounts;

-- DECODE with NULL match (treats NULL = NULL as true):
SELECT DECODE(region, NULL, 'No Region', region) AS region_label
FROM customers;

-- DECODE as ternary:
SELECT DECODE(SIGN(salary - 50000), 1, 'Senior', 'Junior') AS grade
FROM employees;

-- NVL (NULL shorthand):
SELECT NVL(nickname, full_name) AS display_name
FROM users;

-- Standard CASE (preferred for new code, 9i+):
SELECT CASE WHEN salary > 50000 THEN 'Senior' ELSE 'Junior' END AS grade
FROM employees;

sqlite.syntax:
-- CASE WHEN (standard form):
SELECT CASE WHEN salary > 50000 THEN 'Senior' ELSE 'Junior' END AS grade
FROM employees;

-- IFNULL (SQLite does support this one):
SELECT IFNULL(nickname, full_name) AS display_name
FROM users;

-- IIF was added as an alias for CASE WHEN in SQLite 3.32.0:
SELECT IIF(salary > 50000, 'Senior', 'Junior') AS grade
FROM employees;

string split / string to rows.syntax:
-- SQL Server 2016+:
SELECT value
FROM STRING_SPLIT('a,b,c,d', ',');

-- PostgreSQL:
SELECT unnest(string_to_array('a,b,c,d', ',')) AS value;

postgresql.syntax:
-- unnest + string_to_array (most common):
SELECT unnest(string_to_array('a,b,c,d', ',')) AS val;

-- regexp_split_to_table (regex delimiter):
SELECT regexp_split_to_table('a, b,  c , d', '\s*,\s*') AS val;

-- string_to_table (PostgreSQL 14+, cleanest):
SELECT * FROM string_to_table('a,b,c,d', ',') AS val;

-- Use in a JOIN against a table column:
SELECT p.id, tag.val
FROM products p,
unnest(string_to_array(p.tags, ',')) AS tag(val)
WHERE tag.val = 'featured';

json modify / json set.syntax:
-- SQL Server:
SELECT JSON_MODIFY(data, '$.status', 'active') AS updated
FROM users;

-- MySQL:
SELECT JSON_SET(data, '$.status', 'active') AS updated
FROM users;

-- PostgreSQL:
SELECT data || '{"status": "active"}' AS updated
FROM users;

array data type.syntax:
-- PostgreSQL:
CREATE TABLE products (
    id       SERIAL PRIMARY KEY,
    tags     TEXT[],
    scores   INTEGER[]
);

INSERT INTO products (tags, scores)
VALUES (ARRAY['featured','sale'], ARRAY[4,5,3]);

mysql.syntax:
-- JSON array alternative:
CREATE TABLE products (
    id   INT PRIMARY KEY AUTO_INCREMENT,
    tags JSON
);

INSERT INTO products (tags) VALUES (JSON_ARRAY('featured','sale'));

SELECT * FROM products
WHERE JSON_CONTAINS(tags, JSON_QUOTE('featured'));

-- Append to array:
UPDATE products
SET tags = JSON_ARRAY_APPEND(tags, '$', 'new-tag')
WHERE id = 1;

postgresql.syntax:
CREATE TABLE products (
    id     SERIAL PRIMARY KEY,
    tags   TEXT[],
    scores INTEGER[]
);

INSERT INTO products (tags, scores)
VALUES (ARRAY['featured','sale'], ARRAY[4,5,3]);

-- Index access (1-based):
SELECT tags[1] AS first_tag FROM products;

-- Containment: rows where tags includes 'featured':
SELECT * FROM products WHERE tags @> ARRAY['featured'];

-- Overlap: any tag in common:
SELECT * FROM products WHERE tags && ARRAY['sale','new'];

-- Expand to rows:
SELECT id, unnest(tags) AS tag FROM products;

-- GIN index for fast containment:
CREATE INDEX idx_tags ON products USING GIN (tags);

-- Array functions:
SELECT array_length(tags, 1),
       array_append(tags, 'clearance'),
       array_remove(tags, 'sale')
FROM products;

sqlserver.syntax:
-- JSON array alternative (2016+):
ALTER TABLE products ADD tags NVARCHAR(MAX);

UPDATE products
SET tags = JSON_MODIFY(tags, 'append $', 'featured')
WHERE id = 1;

SELECT p.id, s.value AS tag
FROM products p
CROSS APPLY STRING_SPLIT(
    (SELECT STRING_AGG(value,',') FROM OPENJSON(p.tags)), ','
) s;

-- XML alternative:
SELECT t.c.value('.','NVARCHAR(50)') AS tag
FROM products p
CROSS APPLY (
    SELECT CAST('<t>' + REPLACE(p.tags_csv,',','</t><t>') + '</t>' AS XML)
) x(xml_val)
CROSS APPLY xml_val.nodes('/t') t(c);

oracle.syntax:
-- Define a VARRAY type:
CREATE TYPE tag_array AS VARRAY(20) OF VARCHAR2(50);

-- Use it in a table:
CREATE TABLE products (
    id   NUMBER PRIMARY KEY,
    tags tag_array
);

INSERT INTO products VALUES (1, tag_array('featured','sale'));

-- Query: unnest via TABLE():
SELECT p.id, t.COLUMN_VALUE AS tag
FROM products p,
TABLE(p.tags) t
WHERE t.COLUMN_VALUE = 'featured';

-- Nested table (unbounded, out-of-line storage):
CREATE TYPE tag_table AS TABLE OF VARCHAR2(50);

sqlite.syntax:
-- JSON array in a TEXT column:
CREATE TABLE products (
    id   INTEGER PRIMARY KEY,
    tags TEXT  -- store as JSON array string
);

INSERT INTO products (tags) VALUES ('["featured","sale"]');

-- Query elements:
SELECT p.id, j.value AS tag
FROM products p,
json_each(p.tags) j
WHERE j.value = 'featured';

-- Append to array:
UPDATE products
SET tags = json_insert(tags, '$[#]', 'clearance')
WHERE id = 1;

oracle.syntax:
-- Standard UNPIVOT:
SELECT product_id, quarter, sales
FROM quarterly_sales
UNPIVOT (
    sales FOR quarter IN (q1, q2, q3, q4)
);

-- Include NULL rows:
SELECT product_id, quarter, sales
FROM quarterly_sales
UNPIVOT INCLUDE NULLS (
    sales FOR quarter IN (q1 AS 'Q1', q2 AS 'Q2',
                          q3 AS 'Q3', q4 AS 'Q4')
);

-- Custom labels for the key column:
SELECT product_id, quarter, sales
FROM quarterly_sales
UNPIVOT (
    sales FOR quarter IN (q1 AS 'Q1 Sales', q2 AS 'Q2 Sales',
                          q3 AS 'Q3 Sales', q4 AS 'Q4 Sales')
);

postgresql.syntax:
-- Standard INSERT INTO ... SELECT:
INSERT INTO archive_orders (id, customer_id, amount, archived_at)
SELECT id, customer_id, amount, NOW()
FROM orders
WHERE order_date < '2023-01-01';

-- Create and populate:
CREATE TABLE orders_backup AS
SELECT * FROM orders;

-- PostgreSQL-specific SELECT INTO (avoid in stored procedures):
SELECT * INTO orders_backup FROM orders;

-- With ON CONFLICT:
INSERT INTO product_cache (id, price)
SELECT id, price FROM products
ON CONFLICT (id) DO UPDATE SET price = EXCLUDED.price;

-- From a CTE:
WITH recent AS (
    SELECT * FROM orders WHERE order_date >= CURRENT_DATE - 30
)
INSERT INTO recent_orders_summary
SELECT customer_id, COUNT(*), SUM(amount) FROM recent GROUP BY customer_id;

sqlite.syntax:
-- Standard INSERT INTO ... SELECT:
INSERT INTO archive_orders (id, customer_id, amount)
SELECT id, customer_id, amount
FROM orders
WHERE order_date < '2023-01-01';

-- Create and populate:
CREATE TABLE orders_backup AS
SELECT * FROM orders;

-- Wrap in transaction for performance:
BEGIN;
INSERT INTO archive_orders SELECT * FROM orders WHERE order_date < '2023-01-01';
COMMIT;

-- With INSERT OR IGNORE for conflict handling:
INSERT OR IGNORE INTO users_cache
SELECT id, email FROM users_import;

create schema.syntax:
CREATE SCHEMA sales;

CREATE TABLE sales.orders (
    id     INT PRIMARY KEY,
    amount DECIMAL(10,2)
);

SELECT * FROM sales.orders;

mysql.syntax:
-- CREATE SCHEMA = CREATE DATABASE in MySQL:
CREATE SCHEMA sales;
-- Equivalent to:
CREATE DATABASE sales;

-- Use the schema:
USE sales;
CREATE TABLE orders (id INT PRIMARY KEY, amount DECIMAL(10,2));

-- Cross-database reference:
SELECT * FROM sales.orders;

-- CREATE SCHEMA with charset:
CREATE SCHEMA sales
    CHARACTER SET utf8mb4
    COLLATE utf8mb4_unicode_ci;

postgresql.syntax:
-- Create a schema:
CREATE SCHEMA sales;
CREATE SCHEMA sales AUTHORIZATION alice;  -- owned by alice

-- Create a table in the schema:
CREATE TABLE sales.orders (
    id     SERIAL PRIMARY KEY,
    amount NUMERIC(10,2)
);

-- Set the search path for the session:
SET search_path TO sales, public;

-- After setting search_path, unqualified names resolve to sales first:
SELECT * FROM orders;  -- resolves to sales.orders

-- Grant schema usage:
GRANT USAGE ON SCHEMA sales TO reporting_role;
GRANT SELECT ON ALL TABLES IN SCHEMA sales TO reporting_role;

sqlserver.syntax:
-- Create a schema:
CREATE SCHEMA sales AUTHORIZATION dbo;

-- Create table in schema:
CREATE TABLE sales.orders (
    id     INT IDENTITY PRIMARY KEY,
    amount DECIMAL(10,2)
);

-- Transfer an existing table to a different schema:
ALTER SCHEMA sales TRANSFER dbo.legacy_orders;

-- Grant permissions at schema level:
GRANT SELECT ON SCHEMA::sales TO reporting_user;
GRANT EXECUTE ON SCHEMA::sales TO api_user;

-- Four-part reference:
SELECT * FROM myserver.mydb.sales.orders;

oracle.syntax:
-- In Oracle, schema = user:
CREATE USER sales IDENTIFIED BY password
    DEFAULT TABLESPACE users
    QUOTA UNLIMITED ON users;

GRANT CREATE SESSION, CREATE TABLE TO sales;

-- Log in as the sales user:
-- sqlplus sales/password@db

CREATE TABLE orders (id NUMBER PRIMARY KEY, amount NUMBER(10,2));
-- This table is now sales.orders

-- Access from another user:
SELECT * FROM sales.orders;

-- Grant access:
GRANT SELECT ON sales.orders TO reporting_user;

sqlite.syntax:
-- No schemas, but ATTACH DATABASE gives a similar namespace:
ATTACH DATABASE '/data/sales.db' AS sales;
ATTACH DATABASE '/data/hr.db'    AS hr;

-- Cross-database (cross-schema equivalent) query:
SELECT s.id, h.employee_name
FROM sales.orders s
JOIN hr.employees h ON h.id = s.employee_id;

-- The main database is always accessible as 'main':
SELECT * FROM main.products;

-- List attached databases:
PRAGMA database_list;

postgresql.syntax:
-- Database with specific collation:
CREATE DATABASE myapp
    ENCODING 'UTF8'
    LC_COLLATE 'en_US.UTF-8'
    LC_CTYPE   'en_US.UTF-8'
    TEMPLATE template0;

-- Column collation:
CREATE TABLE users (
    username TEXT COLLATE "en-US-x-icu",  -- ICU
    email    TEXT COLLATE "C"             -- byte order
);

-- Ad-hoc comparison with explicit collation:
SELECT * FROM users
WHERE username = 'alice' COLLATE "case_insensitive";

-- Case-insensitive collation (PG 12+ with ICU):
CREATE COLLATION case_insensitive (
    provider = icu,
    locale = 'und-u-ks-level2',
    deterministic = false
);

-- List collations:
SELECT * FROM pg_collation;

sqlserver.syntax:
-- Server/database collation:
CREATE DATABASE myapp
    COLLATE Latin1_General_CI_AS;

-- Column collation:
CREATE TABLE users (
    username NVARCHAR(100) COLLATE Latin1_General_CI_AS,
    sku      VARCHAR(50)   COLLATE Latin1_General_CS_AS  -- case-sensitive
);

-- Ad-hoc collation in query:
SELECT * FROM users
WHERE username = N'alice' COLLATE Latin1_General_CS_AS;

-- Accent-insensitive:
SELECT * FROM users
WHERE username = N'cafe' COLLATE Latin1_General_CI_AI;
-- Matches: cafe, café, CAFE, CAFÉ

-- List available collations:
SELECT * FROM fn_helpcollations();

-- Check database collation:
SELECT DATABASEPROPERTYEX(DB_NAME(), 'Collation');

sqlite.syntax:
-- Column with NOCASE collation:
CREATE TABLE users (
    username TEXT COLLATE NOCASE,  -- ASCII case-insensitive
    email    TEXT COLLATE BINARY   -- default, case-sensitive
);

-- NOCASE in a query:
SELECT * FROM users
WHERE username = 'alice' COLLATE NOCASE;
-- Matches: alice, Alice, ALICE (ASCII only)

-- Index respects collation:
CREATE INDEX idx_username ON users (username COLLATE NOCASE);

-- LOWER() workaround for Unicode case-insensitivity:
SELECT * FROM users
WHERE LOWER(username) = LOWER('Ünïcödé');

-- List collations:
PRAGMA collation_list;

mysql.syntax:
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
  BEGIN
    GET DIAGNOSTICS CONDITION 1 @msg = MESSAGE_TEXT;
  END;

postgresql.syntax:
DO $$
BEGIN
  -- risky
EXCEPTION WHEN others THEN
  RAISE NOTICE 'error: %', SQLERRM;
END;
$$;

sqlserver.syntax:
BEGIN TRY
  INSERT INTO t VALUES (1);
END TRY
BEGIN CATCH
  PRINT ERROR_MESSAGE();
END CATCH;

oracle.syntax:
BEGIN
  INSERT INTO t VALUES (1);
EXCEPTION
  WHEN DUP_VAL_ON_INDEX THEN
    DBMS_OUTPUT.PUT_LINE('duplicate');
  WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE(SQLERRM);
END;

cursor.syntax:
DECLARE cur CURSOR FOR SELECT col FROM t;
OPEN cur;
FETCH NEXT FROM cur INTO @val;
CLOSE cur;
DEALLOCATE cur;

mysql.syntax:
DECLARE cur CURSOR FOR SELECT id FROM t;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;
OPEN cur;
read_loop: LOOP
  FETCH cur INTO v_id;
  IF done THEN LEAVE read_loop; END IF;
END LOOP;
CLOSE cur;

postgresql.syntax:
DECLARE
  cur CURSOR FOR SELECT id FROM t;
  v_id INT;
BEGIN
  OPEN cur;
  LOOP
    FETCH cur INTO v_id;
    EXIT WHEN NOT FOUND;
  END LOOP;
  CLOSE cur;
END;

sqlserver.syntax:
DECLARE cur CURSOR FAST_FORWARD FOR
  SELECT id FROM t;
OPEN cur;
FETCH NEXT FROM cur INTO @id;
WHILE @@FETCH_STATUS = 0
BEGIN
  FETCH NEXT FROM cur INTO @id;
END;
CLOSE cur;
DEALLOCATE cur;

oracle.syntax:
DECLARE
  CURSOR cur IS SELECT id FROM t;
  v_id t.id%TYPE;
BEGIN
  OPEN cur;
  LOOP
    FETCH cur INTO v_id;
    EXIT WHEN cur%NOTFOUND;
  END LOOP;
  CLOSE cur;
END;

mysql.syntax:
SET @sql = CONCAT('SELECT * FROM ', tbl_name);
PREPARE stmt FROM @sql;
EXECUTE stmt USING @param;
DEALLOCATE PREPARE stmt;

postgresql.syntax:
DO $$
DECLARE sql TEXT;
BEGIN
  sql := format('SELECT * FROM %I WHERE id = %L', tbl, val);
  EXECUTE sql;
END;
$$;

oracle.syntax:
DECLARE
  sql_str VARCHAR2(200);
BEGIN
  sql_str := 'UPDATE orders SET status = :1 WHERE id = :2';
  EXECUTE IMMEDIATE sql_str USING 'closed', 99;
END;

postgresql.syntax:
CREATE FUNCTION add_tax(price NUMERIC)
RETURNS NUMERIC
LANGUAGE sql
IMMUTABLE AS $$
  SELECT price * 1.1;
$$;

sqlserver.syntax:
CREATE FUNCTION dbo.add_tax(@price DECIMAL(10,2))
RETURNS DECIMAL(10,2)
AS
BEGIN
  RETURN @price * 1.1;
END;

postgresql.syntax:
CREATE TABLE IF NOT EXISTS orders (id INT PRIMARY KEY);
CREATE INDEX IF NOT EXISTS idx_orders_id ON orders(id);
DROP TABLE IF EXISTS orders;

sqlserver.syntax:
DROP TABLE IF EXISTS dbo.orders;
-- Create workaround:
IF OBJECT_ID('dbo.orders','U') IS NULL
  CREATE TABLE dbo.orders (id INT PRIMARY KEY);

oracle.syntax:
-- Oracle 23c+
CREATE TABLE IF NOT EXISTS orders (id NUMBER PRIMARY KEY);
DROP TABLE IF EXISTS orders;
-- Pre-23c workaround:
BEGIN
  EXECUTE IMMEDIATE 'CREATE TABLE orders (id NUMBER)';
EXCEPTION WHEN OTHERS THEN NULL;
END;

table partitioning.syntax:
-- Declarative range partitioning
CREATE TABLE orders (
  id INT,
  order_date DATE
) PARTITION BY RANGE (order_date);

mysql.syntax:
CREATE TABLE orders (
  id INT,
  order_date DATE
)
PARTITION BY RANGE (YEAR(order_date)) (
  PARTITION p2022 VALUES LESS THAN (2023),
  PARTITION p2023 VALUES LESS THAN (2024),
  PARTITION pmax  VALUES LESS THAN MAXVALUE
);

postgresql.syntax:
CREATE TABLE orders (
  id INT,
  order_date DATE
) PARTITION BY RANGE (order_date);

CREATE TABLE orders_2023
  PARTITION OF orders
  FOR VALUES FROM ('2023-01-01') TO ('2024-01-01');

sqlserver.syntax:
CREATE PARTITION FUNCTION pf_date (DATE)
  AS RANGE RIGHT FOR VALUES ('2023-01-01', '2024-01-01');

CREATE PARTITION SCHEME ps_date
  AS PARTITION pf_date ALL TO ([PRIMARY]);

CREATE TABLE orders (
  id INT,
  order_date DATE
) ON ps_date(order_date);

oracle.syntax:
CREATE TABLE orders (
  id NUMBER,
  order_date DATE
)
PARTITION BY RANGE (order_date)
INTERVAL (NUMTOYMINTERVAL(1, 'YEAR')) (
  PARTITION p_before_2023 VALUES LESS THAN (DATE '2023-01-01')
);

rename table / column.syntax:
-- Table
ALTER TABLE old_name RENAME TO new_name;
-- Column
ALTER TABLE t RENAME COLUMN old_col TO new_col;

mysql.syntax:
RENAME TABLE old_name TO new_name;
-- Column (8.0+):
ALTER TABLE t RENAME COLUMN old_col TO new_col;
-- Column (pre-8.0):
ALTER TABLE t CHANGE old_col new_col INT NOT NULL;

sqlserver.syntax:
-- Table:
EXEC sp_rename 'old_name', 'new_name';
-- Column:
EXEC sp_rename 'dbo.t.old_col', 'new_col', 'COLUMN';

-- Capture into table variable:
DECLARE @ids TABLE (id INT);
INSERT INTO orders (item)
OUTPUT inserted.id INTO @ids
VALUES ('widget');
SELECT * FROM @ids;

-- Return to client:
UPDATE orders SET status = 'closed'
OUTPUT inserted.id, deleted.status
WHERE status = 'open';

oracle.syntax:
DECLARE v_id NUMBER;
BEGIN
  INSERT INTO orders (item)
  VALUES ('widget')
  RETURNING id INTO v_id;
  DBMS_OUTPUT.PUT_LINE('new id: ' || v_id);
END;

sqlite.syntax:
INSERT INTO orders (item)
VALUES ('widget')
RETURNING id, created_at;

DELETE FROM orders WHERE status = 'old'
RETURNING id;

qualify.syntax:
SELECT col, ROW_NUMBER() OVER (PARTITION BY grp ORDER BY col)
FROM t
QUALIFY ROW_NUMBER() OVER (PARTITION BY grp ORDER BY col) = 1;
